from dataclasses import dataclass
from typing import Optional, Union


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional["ASTNode"] = None
    right: Optional["ASTNode"] = None
    operand: Optional["ASTNode"] = None


class Parser:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.length = len(expression)

    def skip_whitespace(self):
        while self.pos < self.length and self.expression[self.pos].isspace():
            self.pos += 1

    def peek(self) -> Optional[str]:
        self.skip_whitespace()
        if self.pos < self.length:
            return self.expression[self.pos]
        return None

    def consume(self) -> Optional[str]:
        self.skip_whitespace()
        if self.pos < self.length:
            char = self.expression[self.pos]
            self.pos += 1
            return char
        return None

    def parse_number(self) -> float:
        start = self.pos
        while self.pos < self.length and (
            self.expression[self.pos].isdigit() or self.expression[self.pos] == "."
        ):
            self.pos += 1

        if start == self.pos:
            raise ValueError("Invalid expression: expected number")

        num_str = self.expression[start : self.pos]
        try:
            return float(num_str)
        except ValueError:
            raise ValueError(f"Invalid number: {num_str}")

    def parse_primary(self) -> ASTNode:
        self.skip_whitespace()

        if self.pos >= self.length:
            raise ValueError("Unexpected end of expression")

        char = self.expression[self.pos]

        if char == "(":
            self.pos += 1
            node = self.parse_expression()
            self.skip_whitespace()
            if self.pos >= self.length or self.expression[self.pos] != ")":
                raise ValueError("Unmatched parenthesis")
            self.pos += 1
            return node

        if char == "-":
            self.pos += 1
            operand = self.parse_primary()
            return ASTNode(type="unary", op="-", operand=operand)

        if char == "+":
            self.pos += 1
            return self.parse_primary()

        if char.isdigit() or char == ".":
            num = self.parse_number()
            return ASTNode(type="number", value=num)

        raise ValueError(f"Invalid token: {char}")

    def parse_term(self) -> ASTNode:
        left = self.parse_primary()

        while True:
            self.skip_whitespace()
            if self.pos >= self.length:
                break

            char = self.expression[self.pos]
            if char == "*" or char == "/":
                self.pos += 1
                right = self.parse_primary()
                left = ASTNode(type="binop", op=char, left=left, right=right)
            else:
                break

        return left

    def parse_expression(self) -> ASTNode:
        left = self.parse_term()

        while True:
            self.skip_whitespace()
            if self.pos >= self.length:
                break

            char = self.expression[self.pos]
            if char == "+" or char == "-":
                self.pos += 1
                right = self.parse_term()
                left = ASTNode(type="binop", op=char, left=left, right=right)
            else:
                break

        return left

    def parse(self) -> ASTNode:
        self.skip_whitespace()
        if self.pos >= self.length:
            raise ValueError("Empty expression")

        node = self.parse_expression()

        self.skip_whitespace()
        if self.pos < self.length:
            raise ValueError(f"Unexpected character: {self.expression[self.pos]}")

        return node


def parse(expression: str) -> ASTNode:
    if expression is None or expression == "":
        raise ValueError("Empty expression")

    parser = Parser(expression)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        assert node.value is not None
        return node.value

    if node.type == "unary":
        assert node.operand is not None
        assert node.op is not None
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        assert node.left is not None
        assert node.right is not None
        assert node.op is not None
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        if node.op == "-":
            return left_val - right_val
        if node.op == "*":
            return left_val * right_val
        if node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
